import { Input } from '../Input/Input'
import { ListWrapper, TasksList } from './List.styles'



export const List = () => {
  return (
    <ListWrapper>
      <Input />

      <TasksList>
        todos.map((item) => (
          <Task task={item} key={item.id} />
        ))
      </TasksList>
    </ListWrapper>
  )
}
